const e=[{id:"pod-02",date:"2026-09-18",title:"Peak, promo match"},{id:"pod-01",date:"2026-09-22",title:"Nino, sulle raccomandazioni e sull'essere il protagonista"},{id:"pod-03",date:"2026-09-25",title:"Marco, vice-allenatore ospite",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi con noi il vice-allenatore Marco."},{type:"line",speaker:"Fallu",text:"Ciao mister."},{type:"line",speaker:"Marco",text:"CINQUE GIRI di corsa E POI INIZIAMO LA PUNTATA. Forza"},{type:"line",speaker:"Fallu",text:"Marco, siamo in onda."},{type:"line",speaker:"Momo",text:"lo sapevo, questo ci fa correre. يا للعار."},{type:"line",speaker:"Cenda",text:`Allora Marco, ami molto la corsa e ho scoperto che il tuo libro preferito è "L'arte di correre" di Murakami, vero? Ce ne parli?`},{type:"line",speaker:"Marco",text:"Sì. Bellissimo. C'è scritto che correre fa bene."},{type:"line",speaker:"Fallu",text:"...ehm tutto qui?"},{type:"line",speaker:"Marco",text:"no, c'è scritto pure che fa bene correre anche quando piove."},{type:"line",speaker:"Cenda",text:"Marco, è un libro sulla disciplina, sulla scrittura, sulla mortalità—"},{type:"line",speaker:"Marco",text:"ALTRI CINQUE GIRI PER CHI INTERROMPE."},{type:"line",speaker:"Momo",text:"يا للعار."},{type:"line",speaker:"Fallu",text:"ultima domanda: perché corri così tanto anche tu, oltre alla squadra?"},{type:"line",speaker:"Marco",text:"perché se mi fermo, devo pensare."},{type:"line",speaker:"Cenda",text:"...oh."}]},{id:"pod-04",date:"2026-10-02",title:"Loris, su quanto era forte come calciatore",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi un ospite storico: Loris, il nostro custode."},{type:"line",speaker:"Fallu",text:"ciao Loris."},{type:"line",speaker:"Loris",text:"ciao. Allora, di cosa volete parlare?"},{type:"line",speaker:"Cenda",text:"ci hanno detto che da giovane eri un calciatore fortissimo. È vero?"},{type:"line",speaker:"Loris",text:`fortissimo è poco. Negli anni '70 mi chiamavano "il muro".`},{type:"line",speaker:"Fallu",text:"il muro? Eri un difensore?"},{type:"line",speaker:"Loris",text:"ero tutto. Difensore, centrocampista, attaccante quando serviva. Non passava niente, da nessuna parte."},{type:"line",speaker:"Momo",text:'"il muro" che ora passa le giornate a urlare ai pulcini, che caduta. يا للعار.'},{type:"line",speaker:"Loris",text:"stavo proprio per dirlo io, Momo. Ma ora te ne puoi andare a-"},{type:"line",speaker:"Cenda",text:"e perché hai smesso?"},{type:"line",speaker:"Loris",text:"(pausa lunga) ...storia lunga. C'erano cose, sul campo, che... lasciamo stare."},{type:"line",speaker:"Fallu",text:"cose? Che tipo di cose?"},{type:"line",speaker:"Loris",text:"niente, niente. Cose di campo."},{type:"line",speaker:"Momo",text:'ecco un altro che fa "..." come Nino, ma con più rabbia. يا للعار.'},{type:"line",speaker:"Loris",text:'io non faccio "...", io faccio silenzi pieni di significato.'},{type:"line",speaker:"Cenda",text:"...e qual è la differenza?"},{type:"line",speaker:"Loris",text:"la differenza è che il mio campo lo sente, il tuo studio no."},{type:"line",speaker:"Fallu",text:"ultima domanda: rigiocheresti, se potessi?"},{type:"line",speaker:"Loris",text:"ogni giorno. Ma certe partite si giocano una volta sola."},{type:"line",speaker:"Cenda",text:"grazie Loris, è stato un piacere."}]},{id:"pod-05",date:"2026-10-09",title:"Admin, l'ospite d'onore",script:[{type:"line",speaker:"Cenda",text:"dovremmo commentare la partita, ma siccome abbiamo perso e non c'è nulla di cui discutere, chiamiamo subito il nostro ospite."},{type:"line",speaker:"fallu",text:"diamo il benvenuto al nostro admin."},{type:"line",speaker:"admin",text:"grazie ragazzi, è un onore essere qui."},{type:"line",speaker:"admin",text:"Momo, fai partire gli applausi finti."},{type:"line",speaker:"momo",text:"pure gli applausi questo vuole, che egocentrico. Ovviamente sarà venuto qua per farsi la marchettata, figuriamoci. يا للعار."},{type:"line",speaker:"Admin",text:"guarda che ti sento Momo: sei sempre un personaggio che ho ideato e scritturato io - so tutto di te. Quindi vedi di stare al tuo posto."},{type:"line",speaker:"Momo",text:"يا للعار."},{type:"line",speaker:"Admin",text:"e poi, riprendendo un famoso detto di un uomo molto saggio, chi sa solo di amatese non sa nulla di Amatese. Quindi lasciami parlare di quello che voglio."},{type:"line",speaker:"Cenda",text:"così mi fai commuovere però citando lo special one. Ma torniamo al motivo per cui sei venuto qui."},{type:"line",speaker:"Fallu",text:"è uscita una tua canzone che fa parte di un racconto-album dove narri una storia di due personaggi dentro a un mirino. Ce ne vuoi parlare?"},{type:"line",speaker:"Admin",text:"Ecco... no. Onestamente la musica è musica, il cinema è cinema... stare a spiegare l'arte perde un po' il senso stesso dell'arte."},{type:"line",speaker:"Admin",text:"quindi semplicemente se vi va ascoltate il mio ultimo brano 'Recitiamo': lo trovate ovunque nei miei profili che sapientemente ho taggato qui (cliccate)."},{type:"line",speaker:"Fallu",text:"insomma, basta un click!"},{type:"line",speaker:"Momo",text:"mmm, Buio Innocente... poteva scegliersi un nome d'arte migliore. يا للعار."},{type:"line",speaker:"Admin",text:"guarda che ti licenzio se continui. Ti tolgo dai prossimi copioni."},{type:"line",speaker:"Momo",text:"..."},{type:"line",speaker:"Cenda",text:"ma tornando alla musica, ci farai presto anche l'inno dell'amatese?"},{type:"line",speaker:"Admin",text:"grazie e alla prossima puntata di 'ma il cenda è sempre fallu'"}]},{id:"pod-06",date:"2026-10-23",title:"Tia, il tifoso occasionale",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi un ospite a sorpresa: Tia."},{type:"line",speaker:"Fallu",text:"...chi?"},{type:"line",speaker:"Tia",text:"ehm, ciao. In realtà non dovevo essere io l'ospite oggi."},{type:"line",speaker:"Cenda",text:'come "non dovevi essere tu"?'},{type:"line",speaker:"Tia",text:"io ero... nei corridoi. Mi hanno chiesto di entrare."},{type:"line",speaker:"Momo",text:"è letteralmente saltato fuori dal nulla, l'admin non aveva nemmeno scritto le sue battute. يا للعار."},{type:"line",speaker:"Tia",text:"(guardando un foglio) ehm, sì, infatti sto improvvisando. Sono della Dugnanese, tifoso occasionale."},{type:"line",speaker:"Fallu",text:"occasionale in che senso?"},{type:"line",speaker:"Tia",text:"nel senso che seguo l'Amatese solo quando perde, mi fa stare meglio con la mia squadra."},{type:"line",speaker:"Cenda",text:"...quindi sei un tifoso della sfortuna altrui?"},{type:"line",speaker:"Tia",text:'si chiama "prospettiva relativa", è scientifico.'},{type:"line",speaker:"Momo",text:"ha inventato una scienza in diretta per giustificarsi, applausi sentiti. يا للعار."},{type:"line",speaker:"Tia",text:"grazie, posso andare? Penso aspettino un altro ospite vero fuori dalla porta."},{type:"line",speaker:"Cenda",text:"vai, vai."},{type:"line",speaker:"Fallu",text:"il prossimo!"}]},{id:"pod-07",date:"2026-10-30",title:"Isa, l'infermiera che conta le battute",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Con noi oggi l'infermiera Isa."},{type:"line",speaker:"Isa",text:"Grazie per avermi invitata. Finalmente qualcuno si ricorda che esisto."},{type:"line",speaker:"Fallu",text:"...scusa?"},{type:"line",speaker:"Isa",text:"niente, niente. È solo che conto le mie battute. Sapete quante ne ho avute fino ad ora?"},{type:"line",speaker:"Cenda",text:"...non lo sappiamo."},{type:"line",speaker:"Isa",text:'nemmeno io, ma sono sicura sia un numero basso. Tipo, esisto solo quando qualcuno si fa male o quando devo dire "ha ragione Nino".'},{type:"line",speaker:"Momo",text:"questa è la prima volta che un personaggio rompe la quarta parete per lamentarsi della propria quarta parete. يا للعار."},{type:"line",speaker:"Fallu",text:"Isa, ma tu sai delle Pietre, della Dugnanese, di Peak... sei quella che sa di più!"},{type:"line",speaker:"Isa",text:"ESATTO. E nessuno me lo chiede mai direttamente!"},{type:"line",speaker:"Cenda",text:"te lo chiediamo ora: che mi dici delle Pietre?"},{type:"line",speaker:"Isa",text:"(lunga pausa) ...sai che ti dico? Ho cambiato idea. Non rispondo."},{type:"line",speaker:"Momo",text:"si è offesa così tanto che ha deciso di fare quello che fa sempre Nino. يا للعار."},{type:"line",speaker:"Isa",text:"esattamente. Ora capite com'è stare al posto suo."},{type:"line",speaker:"Cenda",text:"...grazie Isa, sei stata illuminante."},{type:"line",speaker:"Isa",text:"finalmente qualcuno se ne accorge."}]},{id:"pod-08",date:"2026-11-06",title:"Holygio, sulle simulazioni e i tatuaggi",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Con noi oggi Holygio"},{type:"line",speaker:"Holygio",text:"Ciao a tutti, che gioia essere qui!"},{type:"line",speaker:"Fallu",text:"HG, parliamo dei tuoi tatuaggi: ne hai uno per ogni amatesino?"},{type:"line",speaker:"Holygio",text:"sì! Ne ho ventitré. L'ultimo l'ho fatto la settimana scorsa per il riso—"},{type:"line",speaker:"Cenda",text:"...il riso?"},{type:"line",speaker:"Holygio",text:'(pausa) ...sì. Per il pulcino "Riso". Bellissimo nome, vero?'},{type:"line",speaker:"Momo",text:"sento puzza di copertura narrativa anche qui, ma vado avanti. يا للعار."},{type:"line",speaker:"Fallu",text:"e le simulazioni? Marti dice che a volte fai la finta tonta."},{type:"line",speaker:"Holygio",text:"io? Mai. Sono sempre sincerissima al cento per cento."},{type:"line",speaker:"Cenda",text:"...al cento per cento?"},{type:"line",speaker:"Holygio",text:"(sorriso tirato) al novantotto. Il due per cento è per le sorprese."},{type:"line",speaker:"Momo",text:"il due per cento di Holygio equivale a un mezzo scandalo nazionale, lo sappiamo già. يا للعار."},{type:"line",speaker:"Holygio",text:"Momo, sei cattivo oggi."},{type:"line",speaker:"Momo",text:"sono scritto cattivo, non è colpa mia. يا للعار."},{type:"line",speaker:"Fallu",text:"grazie HG, è stato illuminante."},{type:"line",speaker:"Holygio",text:"grazie a voi, e... salutatemi il gruppo del riso!"},{type:"line",speaker:"Cenda",text:"...certo."}]},{id:"pod-09",date:"2026-11-20",title:"Nino e Cenda, senza Fallu — rapporto padre e figlio",script:[{type:"line",speaker:"Cenda",text:"Bentornati. Oggi puntata speciale: io e Nino, senza Fallu."},{type:"line",speaker:"Momo",text:"Fallu è stato chiuso fuori dallo studio, letteralmente. يا للعار."},{type:"line",speaker:"Fallu (da fuori)",text:"CENDA APRIMI LA PORTA."},{type:"line",speaker:"Cenda",text:"Papà, oggi voglio parlarti di una cosa personale. Tu sei silenzioso. Io parlo sempre. In un certo senso... siamo opposti, ma forse simili."},{type:"line",speaker:"Nino",text:"[...]"},{type:"line",speaker:"Cenda",text:"...sì, esatto, è quello che provo anche io quando faccio il podcast."},{type:"line",speaker:"Fallu (da fuori)",text:"CENDA."},{type:"line",speaker:"Cenda",text:"Papà... ehm Nino, posso confessarti una cosa? A volte mi sento come se anche io non venissi davvero ascoltato, anche se parlo sempre."},{type:"line",speaker:"Nino",text:"[...]"},{type:"line",speaker:"Cenda",text:"(pausa, quasi commosso) ...grazie. Avevo bisogno di sentirlo."},{type:"line",speaker:"Momo",text:"si stanno commovendo per una pausa. Letteralmente per il silenzio. Ma che roba è يا للعار."},{type:"line",speaker:"Fallu (da fuori, più debole)",text:"...mi avete dimenticato, vero?"},{type:"line",speaker:"Nino",text:"[...]"},{type:"line",speaker:"Cenda",text:"(asciugandosi una lacrima) anche tu, papà. Anche tu."}]},{id:"pod-10",date:"2026-11-24",title:"Marti, pippone sull'antico Egitto",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi con noi Marti dall'allevamento."},{type:"line",speaker:"Marti",text:"Grazie mille. Allora, prima di parlare di Amatese, posso dire una cosa? L'antico Egitto è stato sottovalutato dalla narrazione occidentale."},{type:"line",speaker:"Fallu",text:"...scusa, stavamo parlando di calcio."},{type:"line",speaker:"Marti",text:'lo so, ma pensateci: le piramidi sono perfettamente allineate, mentre il nostro campo ha un dislivello che Loris chiama "carattere".'},{type:"line",speaker:"Momo",text:"e siamo già fuori tema al minuto uno. Record. يا للعار."},{type:"line",speaker:"Marti",text:`e poi gli egizi imbalsamavano i corpi per l'eternità, mentre Holygio imbalsama solo le sue scuse "del riso".`},{type:"line",speaker:"Cenda",text:"Marti, era una battuta su Holygio?"},{type:"line",speaker:"Marti",text:"era una battuta su tutto. L'Egitto è una metafora di tutto, se ci pensate."},{type:"line",speaker:"Fallu",text:"...degli amatesini?"},{type:"line",speaker:"Marti",text:"soprattutto degli amatesini. Sono la mia piccola civiltà."},{type:"line",speaker:"Momo",text:"ha appena paragonato dei pulcini a una civiltà millenaria, e in qualche modo aveva senso. يا للعار."},{type:"line",speaker:"Cenda",text:"bene, grazie Marti per questo... viaggio."},{type:"line",speaker:"Marti",text:"prego, alla prossima vi parlo della civiltà Maya, ho già pronto tutto."},{type:"line",speaker:"Fallu",text:"non vediamo l'ora."}]},{id:"pod-11",date:"2026-12-04",title:"rabo, il capo che non è il capo",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi un ospite della Dugnanese: rabo!"},{type:"line",speaker:"rabo",text:"bene, anche se Inzo si prende sempre tutto il merito nelle scene di gruppo."},{type:"line",speaker:"Momo",text:"vero. L'admin scrittura sempre più lui nei copioni. يا للعار."},{type:"line",speaker:"rabo",text:"vedi? Anche tu lo confermi."}]},{id:"pod-13",date:"2027-01-26",title:"Isa, di nuovo (e vuole essere presentata meglio)",script:[{type:"line",speaker:"cenda",text:"Bentorna- si dai, lo sapete già. Con noi oggi Isa."},{type:"line",speaker:"Isa",text:"No, caro il mio Andrea. Presentami come si deve."},{type:"line",speaker:"Cenda",text:"è solo che hai già avuto una puntata del podcast, non mi sembra corretto..."},{type:"line",speaker:"Fallu",text:"Fallo."},{type:"line",speaker:"Cenda",text:"Ma che sorpresa! Guardate chi è venuta a trovarci. La nostra Isa!"},{type:"line",speaker:"Isa",text:"Meglio."},{type:"line",speaker:"Fallu",text:"..."},{type:"line",speaker:"Cenda",text:"allora Isa, cosa ci vuoi raccontare oggi."},{type:"line",speaker:"Momo",text:"...non dovremmo parlare di calcio? يا للعار."},{type:"line",speaker:"Isa",text:"Zitto Momo, sono arrabbiata con tutti voi. Dopo il mio ultimo sfogo non è cambiato nulla."},{type:"line",speaker:"Isa",text:"Sono fondamentale e invisibile. Sai cosa significa? Significa che faccio funzionare tutto e nessuno se ne accorge finché non si rompe qualcosa."},{type:"line",speaker:"Fallu",text:"è vero, tecnicamente-"},{type:"line",speaker:"Isa",text:"Ho avuto una scena con Nino dove dico cose bellissime e alla fine l'admin me le ha tagliate."},{type:"line",speaker:"Isa",text:"Non è giusto! Nessuno si ricorda di quella scena."},{type:"line",speaker:"Cenda",text:"...io sì."},{type:"line",speaker:"Isa",text:"bravo. Sei l'unico. Perché era tra due scene di Nonno Paul- come posso competere?"},{type:"line",speaker:"Fallu",text:"In effetti."},{type:"line",speaker:"Isa",text:"non voglio più sapere cose per conto degli altri, non voglio più essere il contenitore di nessuno."},{type:"line",speaker:"Isa",text:"La prossima stagione voglio sbagliare qualcosa di mio, avere un mio arco narrativo e decidere io quando chiudere i dialoghi. Come farò adesso."}]},{id:"pod-14",date:"2027-02-08",title:"Marti, la storia di Cassina Amata",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi di nuovo la nostra Marti."},{type:"line",speaker:"Marti",text:"Ciao a tutti! Allora, oggi voglio parlarvi di Cassina Amata."},{type:"line",speaker:"Fallu",text:"finalmente, qualcosa di pertinente."},{type:"line",speaker:"Marti",text:`Cassina Amata nasce come cascina agricola nel 1887. Il nome originale era "Cascina dell'Amata" — non "amata" come aggettivo, ma come soprannome di una donna.`},{type:"line",speaker:"Cenda",text:"...quale donna?"},{type:"line",speaker:"Marti",text:`non si sa. I documenti catastali dicono solo "l'Amata" e poi basta...`},{type:"line",speaker:"Marti",text:"poi nel dopoguerra viene creato un campo sportivo: prima c'erano i buoi, poi i calciatori... fondamentalmente la stessa cosa."},{type:"line",speaker:"Fallu",text:"...Marti."},{type:"line",speaker:"Marti",text:"è un'osservazione storica, non un insulto."},{type:"line",speaker:"Cenda",text:"e le Pietre? Nella storia di Cassina Amata c'entrano?"},{type:"line",speaker:"Marti",text:`(pausa) ...sì. Ho trovato un documento del '74. Diceva che il campo "custodisce ciò che la terra chiede in prestito". Pensavo fosse una poesia ma mi sbagliavo`},{type:"line",speaker:"Fallu",text:"che intendi?"},{type:"line",speaker:"Marti",text:"Che la terra fa sul serio a quanto pare... non sono solo fantasie."},{type:"line",speaker:"Momo",text:"Crazy, è arrivata alla lore più importante partendo dai buoi. يا للعار."},{type:"line",speaker:"Marti",text:`e poi c'è un'altra cosa. "L'Amata" nel documento del '74 ricompare come testimone di una riunione...`},{type:"line",speaker:"Cenda",text:"...la stessa persona del 1887?"},{type:"line",speaker:"Marti",text:"(pausa) il documento dice che aveva gli stessi occhi, ma magari ve ne parlerò meglio in un'altra puntata."},{type:"line",speaker:"Marti",text:"così l'admin è costretto a scritturarmi ancora."},{type:"line",speaker:"Fallu",text:"..."}]},{id:"pod-15",date:"2027-02-14",title:"San Valentino, con Nino",script:[{type:"line",speaker:"Cenda",text:"Bentornati! San Valentino, e con noi di nuovo Nino."},{type:"line",speaker:"Fallu",text:'Nino, oggi vorremmo affrontare la tua frase iconica: "sono piccolo ma ci vedo molto lungo". Cosa significa esattamente?'},{type:"line",speaker:"Nino",text:"[...]"},{type:"line",speaker:"Cenda",text:"...wow."},{type:"line",speaker:"Fallu",text:"cioè?"},{type:"line",speaker:"Cenda",text:"ha appena spiegato tutta la stagione in una pausa."},{type:"line",speaker:"Momo",text:"io ero pronto a tagliare per silenzio morto e invece era la rivelazione del secolo. يا للعار."},{type:"line",speaker:"Fallu",text:"Nino, ultima domanda, è San Valentino: cosa consiglieresti a chi cerca l'amore?"},{type:"line",speaker:"Nino",text:"[...]"},{type:"line",speaker:"Cenda",text:"(commosso) ...anche io spero che vada bene per loro."},{type:"line",speaker:"Fallu",text:"aspetta, di chi stiamo parlando?"},{type:"line",speaker:"Cenda",text:"non lo so, ma ho fiducia."},{type:"line",speaker:"Momo",text:"questo podcast esiste solo perché Nino lascia spazi vuoti e noi ci infiliamo dentro i nostri problemi. يا للعار."},{type:"line",speaker:"Nino",text:"[...]"},{type:"line",speaker:"Cenda",text:"...hai ragione anche su questo."}]},{id:"pod-12",date:"2027-02-26",title:"Nonno Paul, su quanto soffre la partita",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi una leggenda: Nonno Paul."},{type:"line",speaker:"Nonno Paul",text:"Grazie ragazzi. Vuoi una caramella?"},{type:"line",speaker:"Fallu",text:"io sì, grazie."},{type:"line",speaker:"Cenda",text:"Nonno Paul, per smorzare un po' il racconto, narraci di quanto soffri durante le partite."},{type:"line",speaker:"Nonno Paul",text:`Soffro tantissimo. Una volta, nel '74, eravamo sotto 5 a 0 all'intervallo e mio fratello mi disse: "Paolino, o vinciamo o moriamo qui".`},{type:"line",speaker:"Cenda",text:"e poi?"},{type:"line",speaker:"Nonno Paul",text:"vincemmo 6 a 5."},{type:"line",speaker:"Fallu",text:"incredibile."},{type:"line",speaker:"Nonno Paul",text:"sì, è incredibile perché non è mai successo. Me lo sono inventato ora."},{type:"line",speaker:"Momo",text:"anche i flashback ormai sono fake news. يا للعار."},{type:"line",speaker:"Cenda",text:"...quindi gli aneddoti del '74 non sono veri?"},{type:"line",speaker:"Nonno Paul",text:"alcuni sì, altri li invento sul momento. Il bello è che a una certa età nessuno ti controlla più."},{type:"line",speaker:"Fallu",text:"e qual è la differenza tra i veri e i finti?"},{type:"line",speaker:"Nonno Paul",text:"(sorridendo) i finti hanno sempre un finale più bello."},{type:"line",speaker:"Nonno Paul",text:"Non è l'amore che muove il mondo ma la sete di conoscenza, così come la speranza e l'immaginazione."},{type:"line",speaker:"Nonno Paul",text:"L'amore è conseguenza o un incidente di percorso. Vuoi una caramella anche tu, Momo?"},{type:"line",speaker:"Momo",text:"che timeline sto vivendo? Nonno Paul che cita Caparezza e mi offre una caramella يا للعار."}]},{id:"pod-16",date:"2027-02-27",title:"Admin, la seconda volta",script:[{type:"line",speaker:"Cenda",text:"ma quindi andiamo a far serata, venerdì?"},{type:"line",speaker:"Momo",text:"ragazzi, siamo in onda."},{type:"line",speaker:"Cenda",text:"oh... ben ritrovati al nostro magico podcast, sono sempre io: Andrea Cenda. E con me naturalmente è presente il mio co-conduttore Fallu"},{type:"line",speaker:"fallu",text:"ciao"},{type:"line",speaker:"Cenda",text:"e anche il nostro super-ospite: l'admin. Grazie per essere tornato a trovarci."},{type:"line",speaker:"admin",text:"Grazie a voi, è sempre un privilegio."},{type:"line",speaker:"momo",text:"...se è tornato c'è solo un motivo, maledetto... deve farsi la promo."},{type:"line",speaker:"momo",text:"Anche oggi non si parlerà di calcio, يا للعار"},{type:"line",speaker:"admin",text:"ti ricordo che ti sento perché scrivo io i tuoi pensieri."},{type:"line",speaker:"Admin",text:"Ma comunque ti sbagli, caro il mio Momo. Non sono venuto qui per parlare del mio singolo che è uscito da poco e che potete ascoltare sul mio profilo."},{type:"line",speaker:"Admin",text:"Anzi per la verità non mi interessa proprio dire che ormai ho pubblicato già 6 canzoni del mio album-libro, che potete sempre ascoltare sul mio profilo."},{type:"line",speaker:"Admin",text:"Sarebbe davvero un peccato non parlare di Amatese per raccontare la mia nuova uscita e invitare all'ascolto dei miei brani tutti gli spettatori."},{type:"line",speaker:"Momo",text:"quanto ti soffro. يا للعار"},{type:"line",speaker:"Cenda",text:"Allora parliamo di amatese, dai. Come giudichi l'ultima partita dei ragazzi?"},{type:"line",speaker:"Fallu",text:"Noi non ci siamo ancora ripresi."},{type:"line",speaker:"Admin",text:"Beh, effettivamente è stata una partita 'fino all'ultimo respiro' per citare il mio nuovo singolo, di cui non ho la minima intenzione di parlarne."},{type:"line",speaker:"Momo",text:"Basta, io stacco tutto."},{type:"stage",text:"schermo nero"}]},{id:"pod-17",date:"2027-03-08",title:"Podcast tutto al femminile — Isa, Gio, Holygio, Marti e Gaia",script:[{type:"line",speaker:"Isa",text:"Bentornate al nostro podcast femminile non autorizzato. Sono Isa, oggi conduciamo noi donne."},{type:"line",speaker:"Gio",text:"Tremate uomini."},{type:"line",speaker:"Isa",text:"Punto uno: quante battute avete avuto questa stagione?"},{type:"line",speaker:"Gaia",text:'poche. La mia storia è "scopre il segreto di Pashy e poi lo perdona". Ma che roba è?'},{type:"line",speaker:"Holygio",text:'io avevo il riso, la Dugnanese, il tradimento... e una "nuova acconciatura" datami ogni volta come contentino.'},{type:"line",speaker:"Marti",text:`io sono "quella dell'allevamento". Ho un cognome?`},{type:"line",speaker:"Gio",text:"io sto meglio perché filmo... se non ci sono direttamente nelle scene, comunque appaio dietro la telecamera. Ma non mi basta più."},{type:"line",speaker:"Holygio",text:"io capisco che la storia è su Nino, sul campo e sul Presidente; che si dovrebbe parlare di più di calcio e bla bla bla"},{type:"line",speaker:"Holygio",text:"Ma noi siamo lì ogni giorno. Cuciniamo, medichiamo, filmiamo, scopriamo cose... senza di noi l'amatese non esiste."},{type:"line",speaker:"Isa",text:"Eccoci quindi al punto finale: la prossima stagione. Cosa vogliamo, anzi, cosa pretendiamo."},{type:"line",speaker:"Gaia",text:"un arco che non passi per nessun uomo. Voglio essere la protagonista."},{type:"line",speaker:"Gio",text:"Io voglio girare una scena dove la telecamera sono io, non quello che riprendo."},{type:"line",speaker:"Isa",text:"io voglio smettere di essere il personaggio che sa tutto e non dice niente finché non serve."},{type:"line",speaker:"Holygio",text:"Voglio essere io la villain, seriamente però. Inzo non viene mai alle partite, rabo è rabo. Non è giusto che lo facciano loro."},{type:"line",speaker:"Momo",text:"...admin, se stai ascoltando: prendi nota. يا للعار."},{type:"line",speaker:"Gaia",text:"e tu, Marti?"},{type:"line",speaker:"Marti",text:"io sto bene così, grazie. Ho già delle rivelazioni troppo importanti ai fini della trama. Sono insostituibile."}]},{id:"pod-18",date:"2027-03-16",title:"Il Sindacato degli Esclusi",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi una puntata... non prevista. Abbiamo ricevuto una delegazione."},{type:"line",speaker:"Voce 1",text:"siamo il Sindacato degli Esclusi. Abbiamo fatto il provino per entrare nella serie ma siamo stati rifiutati."},{type:"line",speaker:"Fallu",text:"...tutti?"},{type:"line",speaker:"Voce 2",text:"tutti. Una vergogna."},{type:"line",speaker:"Voce 2",text:`a me l'admin ha detto che il mio silenzio non era "narrativamente denso" come quello di Nino.`},{type:"line",speaker:"Cenda",text:"e com'è il tuo silenzio?"},{type:"line",speaker:"Voce 2",text:"..."},{type:"line",speaker:"Momo",text:"oggettivamente identico. يا للعار."},{type:"line",speaker:"Voce 3",text:"il problema è che l'admin scrive solo chi gli sta simpatico."},{type:"line",speaker:"Voce 1",text:"Tia era nei corridoi per caso e ha avuto una puntata intera del podcast. Noi abbiamo preparato materiale per settimane, ma nulla"},{type:"line",speaker:"Voce 2",text:"io vengo tutte le domeniche a vedere l'amatese ma siccome non saluto l'admin da un anno allora non mi ha scritturato per neanche un secondo. Che rancoroso, bah."},{type:"line",speaker:"Cenda",text:"avete mai fatto ricorso formalmente?"},{type:"line",speaker:"Voce 1",text:`sì. L'admin ha risposto che la storia era "già bilanciata". Lo odio. Ma poi un protagonista che non parla dai, ma siamo seri.`},{type:"line",speaker:"Fallu",text:"tecnicamente Nino è molto efficace—"},{type:"line",speaker:"Voce 3",text:"lo so che è efficace! È efficace ma io avevo un monologo di tre minuti sulla terza categoria e non me lo ha fatto dire nessuno!"},{type:"line",speaker:"Voce 3",text:'allora. "La terza categoria non è solo una divisione calcistica. È uno stato mentale. È—"'},{type:"line",speaker:"Fallu",text:"ci credo che ti ha scartato, mi cadono le-."},{type:"line",speaker:"Cenda",text:"Parleremo con l'admin e vi faremo sapere, grazie per essere passati."}]},{id:"pod-19",date:"2027-03-23",title:"Pashy, sull'essere playboy",script:[{type:"line",speaker:"Cenda",text:"Bentornati, oggi con noi il professor Pashy!"},{type:"line",speaker:"Pashy",text:'Buonasera. Anche se "playboy" è un termine che mi è stato... assegnato, diciamo, dalla produzione.'},{type:"line",speaker:"Fallu",text:"ma tu non ti ci ritrovi?"},{type:"line",speaker:"Pashy",text:"ecco, il punto è che la scienza non si addice ai cliché. Io definirei il mio approccio più... empirico-romantico."},{type:"line",speaker:"Momo",text:"traduzione: rimorchia ma non quaglia. يا للعار."},{type:"line",speaker:"Pashy",text:"Momo, ti ricordo che le tue battute sono scritte da—"},{type:"line",speaker:"Momo",text:"lo so, lo so, dall'admin, lo sappiamo tutti, يا للعار."},{type:"line",speaker:"Cenda",text:"e con Gaia? C'è qualcosa, professore?"},{type:"line",speaker:"Pashy",text:"...ehm Gaia è la mia assistente. Il rapporto è puramente—"},{type:"line",speaker:"Fallu",text:"professore, ha arrossito."},{type:"line",speaker:"Pashy",text:"è il riscaldamento dello studio."},{type:"line",speaker:"Cenda",text:"ci sono 15 gradi."},{type:"line",speaker:"Pashy",text:"...è il riscaldamento globale."},{type:"line",speaker:"Momo",text:"il primo scienziato della storia a usare il cambiamento climatico come scusa per una cotta. يا للعار."}]},{id:"pod-20",date:"2027-03-27",title:"Pres, sul suo ruolo nella serie (incazzato)",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi un ospite... particolare: il Presidente."},{type:"line",speaker:"Pres",text:"Sì, sono qui, e voglio dire una cosa."},{type:"line",speaker:"Fallu",text:"prego."},{type:"line",speaker:"Pres",text:"per trentasette episodi sono stato il villain. IO. Quello che ha sponsorizzato tutto, che ha comprato la struttura, che paga gli stipendi."},{type:"line",speaker:"Cenda",text:"beh, in realtà hai anche sabotato la squadra—"},{type:"line",speaker:"Pres",text:"SÌ MA AVEVO PAURA, È DIVERSO."},{type:"line",speaker:"Momo",text:"si sta difendendo da solo in un podcast meta, livello di disperazione altissimo. يا للعار."},{type:"line",speaker:"Pres",text:"Momo, anche tu mi prendi in giro?"},{type:"line",speaker:"Momo",text:"tutti ti prendono in giro, è scritto così. يا للعار."},{type:"line",speaker:"Pres",text:"(sospiro) ...va bene. Almeno alla fine mi sono scusato."},{type:"line",speaker:"Fallu",text:"questo è vero, e la squadra ti ha perdonato."},{type:"line",speaker:"Pres",text:"esatto! Grazie Fallu, finalmente qualcuno con un po' di empatia."},{type:"line",speaker:"Cenda",text:"comunque sì, anche tu hai fatto il discorso più lungo di Nino in tutta la stagione."},{type:"line",speaker:"Pres",text:"(pausa) ...questo non dovevi dirlo."}]},{id:"pod-21",date:"2027-04-01",title:"Inzo (Dugnanese), sull'essere il capo dei villain",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi con noi Inzo, il capo della Dugnanese."},{type:"line",speaker:"Inzo",text:"Salve. Sono onorato di essere il capo dei villain di questa storia."},{type:"line",speaker:"Fallu",text:"come ti senti dopo il licenziamento?"},{type:"line",speaker:"Inzo",text:"liberato, sinceramente. Trent'anni— scusate, tre anni a fare il villain part-time sono pesanti."},{type:"line",speaker:"Momo",text:"il capo dei villain non sa nemmeno gestire una chiave USB, capo de che. يا للعار."},{type:"line",speaker:"Inzo",text:"...Momo, quella è una cosa che ancora non sai."},{type:"line",speaker:"Momo",text:"lo so perché lo scrive l'admin e l'admin parla con me a volte quando è ubriaco. يا للعار."},{type:"line",speaker:"Inzo",text:"(pausa lunga) ...va bene, ignoro."},{type:"line",speaker:"Cenda",text:"Inzo, ultima domanda: rifaresti tutto?"},{type:"line",speaker:"Inzo",text:"la parte del villain, sì. La parte in cui rabo non butta le cose, assolutamente no."},{type:"line",speaker:"Momo",text:"STOP. SPOILER. STACCO TUTTO."},{type:"stage",text:"schermo nero"}]},{id:"pod-22",date:"2027-04-03",title:"Pres, il ritorno (fa ammenda anche con Momo)",script:[{type:"line",speaker:"Cenda",text:"Bentornati! Oggi torna un ospite che conoscete già: il Presidente."},{type:"line",speaker:"Fallu",text:"ciao Pres, ultima volta non era andata benissimo."},{type:"line",speaker:"Pres",text:"lo so, lo so. Ma oggi è diverso. Volevo tornare per dire le cose per bene, stavolta."},{type:"line",speaker:"Momo",text:"vediamo se anche stavolta si scusa con tutti tranne con me. يا للعار."},{type:"line",speaker:"Pres",text:"Momo, in realtà... volevo scusarmi anche con te."},{type:"line",speaker:"Momo",text:"...cosa?"},{type:"line",speaker:"Pres",text:"ho letto i copioni. So che ti fanno dire cose cattive su di me da ventisette episodi. Non era colpa tua."},{type:"line",speaker:"Momo",text:"...non so cosa dire. Per la prima volta in assoluto. يا للعار, ma con affetto."},{type:"line",speaker:"Cenda",text:"Pres, come sono andate le cose dopo la riunione con la squadra?"},{type:"line",speaker:"Pres",text:"bene. Davvero bene. Loris mi parla di nuovo, anche se solo per dirmi quanto costa l'erba."},{type:"line",speaker:"Fallu",text:"e con Pashy?"},{type:"line",speaker:"Pres",text:"gli ho detto che è insostituibile. E lo penso davvero."},{type:"line",speaker:"Cenda",text:"e con Peak?"},{type:"line",speaker:"Pres",text:"(ridendo) ...vedrete presto"},{type:"line",speaker:"Momo",text:"il presidente più cambiato della storia dei podcast meta-narrativi. يا للعار, in senso buono però."},{type:"line",speaker:"Fallu",text:"ultima domanda: cosa ti aspetti dalla prossima stagione?"},{type:"line",speaker:"Pres",text:"niente sabotaggi, stavolta promessi da me. E magari... la seconda categoria, se ce la meritiamo davvero."},{type:"line",speaker:"Cenda",text:"grazie Pres, e bentornato tra noi."},{type:"line",speaker:"Pres",text:"grazie a voi. E grazie a tutti per avermi dato un'altra possibilità."}]},{id:"pod-23",date:"2027-04-10",title:"Gio, il tennis come metafora dell'Amatese",script:[{type:"line",speaker:"Cenda",text:"'Il cenda è sempre falluuuuuuuuuuuu, ma il cenda è sempre falluuuuuuuuuu'"},{type:"line",speaker:"Fallu",text:"ciao, sono io fallu."},{type:"line",speaker:"Cenda",text:"Ben ritrovati al nostro podcast dove si parla di calcio e amatese. Con noi la nostra stupenda amica e fan: Giorgia! Applauso!"},{type:"line",speaker:"Gio",text:"Tennis."},{type:"line",speaker:"Fallu",text:"..."},{type:"line",speaker:"Gio",text:"Tennis."},{type:"line",speaker:"Cenda",text:"va bene, parliamo di Tennis."},{type:"line",speaker:"Momo",text:"giuro che faccio una sciocchezza se non parliamo di calcio neanche oggi. يا للعار."},{type:"line",speaker:"Gio",text:"Parlerò dell'amatese e di calcio, ma per farlo devo parlare di tennis."},{type:"line",speaker:"Gio",text:"ritengo che sia inutile soffermarmi sulla partita, e non perché questi monologhi sono stati scritti a maggio scorso dall'admin, sia chiaro"},{type:"line",speaker:"Gio",text:"ma semplicemente perché l'amatese indaga qualcosa di più intimo che tutti abbiamo dentro."},{type:"line",speaker:"Cenda",text:"Non so dove vuoi andare a parare ma ti ascoltiamo."},{type:"line",speaker:"Gio",text:"L'amatese non gioca sul prato perfetto di San Siro e non è aggraziata da vedere; tuttavia, esattamente come la terra rossa del Roland Garros, è passione, terra e sudore."},{type:"line",speaker:"Gio",text:"Potrei dirvi che il giallo-blu sporco di fango è romantico tanto quanto una dedica scritta sulla telecamera a fine partita."},{type:"line",speaker:"Fallu",text:"Ci sta."},{type:"line",speaker:"Cenda",text:"quindi è per questo che nella serie fai la reporter?"},{type:"line",speaker:"Gio",text:"bravo, hai colto il punto. Nella vita mi piace cogliere gli sguardi che nessuno nota, le palline che nessuno tira e le racchette che nessuno guarda."},{type:"line",speaker:"Momo",text:"CALCIOOOOOOOOOOOO, dovete parlare di calcio!"},{type:"line",speaker:"Fallu",text:"tennis."}]},{id:"pod-24",date:"2027-04-13",title:"Marti e Holygio insieme, dopo tutto",script:[{type:"line",speaker:"Marti",text:"(agli amatesini) Ciao ciao tesori."},{type:"line",speaker:"Holygio",text:"Siamo qui insieme per raccontarvi come è andata davvero."},{type:"line",speaker:"Cenda",text:"quindi i biglietti per le Hawaii?"},{type:"line",speaker:"Marti",text:"sul tavolo. Decido io quando riguardarli."},{type:"line",speaker:"Holygio",text:"capito. Ancora capito."},{type:"line",speaker:"Momo",text:"tenerezza forzata contrattualmente, ma va bene lo stesso. يا للعار."}]},{id:"pod-25",date:"2027-04-17",title:"Ultima puntata — Fallu ringrazia tutti",script:[{type:"line",speaker:"Fallu",text:"Bentornati all'ultima puntata della stagione."},{type:"line",speaker:"Cenda",text:"oggi tocca a Fallu, che vuole dire due parole."},{type:"line",speaker:"Fallu",text:"grazie. Allora — questa stagione è stata... tanto. Pietre, Pres, Peak, Pashy. Troppe P, sinceramente."},{type:"line",speaker:"Momo",text:'anche "podcast" inizia con la P, casualità? يا للعار.'},{type:"line",speaker:"Fallu",text:'appunto. Volevo solo ringraziare tutti quelli che ci hanno seguito, anche quando io dicevo solo "..." per episodi di fila.'},{type:"line",speaker:"Cenda",text:"è il tuo turno, Fallu. Sei stato il vero Nino di questo podcast."},{type:"line",speaker:"Fallu",text:"(pausa lunga) ..."},{type:"line",speaker:"Momo",text:"lo ha appena fatto di nuovo, perfetto, chiusura circolare. يا للعار."},{type:"line",speaker:"Cenda",text:"grazie a tutti, ci si rivede in stagione 2!"},{type:"line",speaker:"Fallu",text:"e grazie soprattutto a Momo, che—"},{type:"line",speaker:"Momo",text:"non iniziare, io sto già andando via. يا للعار."},{type:"line",speaker:"Momo",text:"per l'ultima volta, è stato un piacere soffrire con voi."},{type:"stage",text:"schermo nero"}]}];export{e as p};
